"workspaceUsage.userList.tableHeader.projectMessages":`Skilaboð verkefnis`,"workspaceUsage.userList.tableHeader.seatType":`Sætistegund`,"workspaceUsage.userList.tableHeader.toolMessages":`Samskipti verkfæra`,"workspaceUsage.userList.tableHeader.toolMessagesTooltip":`Mælir virkni verkfærabeiðna. Þar sem hvert notandaskilaboð getur kallað fram margar slíkar beiðnir geta tölurnar verið mjög breytilegar, jafnvel hjá notendum með svipaðan heildarfjölda skilaboða.`,"workspaceUsage.usersTab":`Notendur`,"workspaceUsage.weeklyActiveUsersMetric":`Fjöldi einstakra virkra notenda á viku`,"workspaceUsage.workspaceAnalyticsTitle":`Greining á vinnusvæði`,wqXY9B:moe,wrM5BY:hoe,"writing-entry.paraphrase.content-type-academic-writing":`fræðileg skrif`,"writing-entry.paraphrase.content-type-email":`tölvupóstur`,"writing-entry.paraphrase.content-type-label":`Tegund efnis`,"writing-entry.paraphrase.content-type-message":`bein skilaboð`,"writing-entry.paraphrase.content-type-prd":`PRD`,"writing-entry.paraphrase.content-type-resume":`ferilskrá`,"writing-entry.paraphrase.content-type-social-post":`samfélagsmiðlafærsla`,"writing-entry.paraphrase.content-type-text":`texti`,"writing-entry.paraphrase.example-cover-letter":`Endurorðaðu þetta umsóknarbréf`,"writing-entry.paraphrase.example-cover-letter-preview":`fyrir umsókn um hönnunarstarf`,"writing-entry.paraphrase.example-cover-letter-source":`Ég sæki um af miklum áhuga því teymið ykkar er að þróa vörur sem eru vel ígrundaðar, skýrar og gagnlegar, og það er nákvæmlega sú vinna sem ég vil leggja mitt af mörkum til.`,"writing-entry.paraphrase.example-follow-up-email":`Umorðaðu þennan tölvupóst`,"writing-entry.paraphrase.example-follow-up-email-preview":`um stöðuhækkun`,"writing-entry.paraphrase.example-follow-up-email-source":`Takk aftur fyrir fundinn í dag. Mig langaði að fylgja eftir umræðunni um fjárhagsáætlunina og athuga hvort þú þurfir eitthvað meira frá mér fyrir næstu viku.`,"writing-entry.paraphrase.example-prd-summary":`Umorðaðu þessa vöruskýrslu`,"writing-entry.paraphrase.example-prd-summary-preview":`fyrir stöðuuppfærslu til hagsmunaaðila`,"writing-entry.paraphrase.example-prd-summary-source":`Þessi eiginleiki hjálpar nýjum notendum að komast hraðar í kjarnavinnuflæðið með því að fækka uppsetningarskrefum og skýra næsta skref eftir upphafsleiðsögn.`,"writing-entry.paraphrase.example-quick-message":`Umorðaðu þennan myndatexta`,"writing-entry.paraphrase.example-quick-message-preview":`fyrir Instagram-færslu`,"writing-entry.paraphrase.example-quick-message-source":`Gullstund, hafgola og sólsetur sem fær þig til að hætta að skrolla.`,"writing-entry.paraphrase.example-resume-bullet":`Endurorðaðu þennan ferilskrárlið`,"writing-entry.paraphrase.example-resume-bullet-preview":`fyrir ferilskrá hugbúnaðarverkfræðings`,"writing-entry.paraphrase.example-resume-bullet-source":`Þróaði innri verkfæri sem styttu vikulega skýrslugerð um 6 klst. og bættu yfirsýn teymisins yfir útgáfuhindranir.`,"writing-entry.paraphrase.example-team-update":`Umorðaðu þessi skilaboð`,"writing-entry.paraphrase.example-team-update-preview":`fyrir LinkedIn-skilaboð`,"writing-entry.paraphrase.example-team-update-source":`Við löguðum innskráningarvandann, en útgáfunni seinkar enn því lokayfirferð QA fann nokkrar afturkomnar villur á farsíma.`,"writing-entry.paraphrase.generated-prompt":`Endurorðaðu eftirfarandi. Tegund efnis: {contentType}. Tónn: {tone}. Lengd: {length}.{sourceSeparator}{sourceText}`,"writing-entry.paraphrase.length-bullet-points":`punktar`,"writing-entry.paraphrase.length-label":`Lengd`,"writing-entry.paraphrase.length-longer":`lengra`,"writing-entry.paraphrase.length-novel":`skáldsaga`,"writing-entry.paraphrase.length-same":`sama lengd`,"writing-entry.paraphrase.length-same-prompt":`álíka langt`,"writing-entry.paraphrase.length-short":`stutt`,"writing-entry.paraphrase.prompt-lead":`Umorðaðu þetta`,"writing-entry.paraphrase.source-label":`Upprunalegur texti`,"writing-entry.paraphrase.submit-label":`Opna í ChatGPT`,